package com.example.harshatrial;

import android.content.SharedPreferences;
import android.database.Cursor;
import android.os.Bundle;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.google.android.material.appbar.MaterialToolbar;

public class AddParkingActivity extends AppCompatActivity {

    public static final String EXTRA_PARKING_ID = "extra_parking_id";

    private EditText etParkingName, etAddress, etTotalSlots, etPricePerHour, etFeatures;
    private Button btnSaveParking;
    private DatabaseHelper dbHelper;
    private int ownerId;
    private int editParkingId = -1;
    private int currentAvailableSlots = -1;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_add_parking);

        dbHelper = new DatabaseHelper(this);
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        ownerId = sp.getInt("userId", -1);

        etParkingName = findViewById(R.id.etParkingName);
        etAddress = findViewById(R.id.etAddress);
        etTotalSlots = findViewById(R.id.etTotalSlots);
        etPricePerHour = findViewById(R.id.etPricePerHour);
        etFeatures = findViewById(R.id.etFeatures);
        btnSaveParking = findViewById(R.id.btnSaveParking);
        MaterialToolbar toolbar = findViewById(R.id.toolbar);
        toolbar.setNavigationOnClickListener(v -> finish());

        editParkingId = getIntent().getIntExtra(EXTRA_PARKING_ID, -1);
        if (editParkingId != -1) {
            btnSaveParking.setText(R.string.update_parking_location);
            preloadParking(editParkingId);
        }

        btnSaveParking.setOnClickListener(v -> {
            String name = etParkingName.getText().toString().trim();
            String address = etAddress.getText().toString().trim();
            String totalSlotsStr = etTotalSlots.getText().toString().trim();
            String priceStr = etPricePerHour.getText().toString().trim();
            String features = etFeatures.getText().toString().trim();

            if (name.isEmpty() || address.isEmpty() || totalSlotsStr.isEmpty() || priceStr.isEmpty()) {
                Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
                return;
            }

            int totalSlots = Integer.parseInt(totalSlotsStr);
            double pricePerHour = Double.parseDouble(priceStr);

            if (editParkingId != -1) {
                int safeAvailable = currentAvailableSlots == -1 ? totalSlots : currentAvailableSlots;
                int updated = dbHelper.updateParking(editParkingId, name, address, totalSlots, safeAvailable, features, pricePerHour);
                if (updated > 0) {
                    Toast.makeText(this, "Parking location updated!", Toast.LENGTH_SHORT).show();
                    finish();
                    return;
                }
                Toast.makeText(this, "Error updating parking", Toast.LENGTH_SHORT).show();
                return;
            }

            long result = dbHelper.addParking(ownerId, name, address, totalSlots, features, pricePerHour);
            if (result > 0) {
                Toast.makeText(this, "Parking location added!", Toast.LENGTH_SHORT).show();
                finish();
            } else {
                Toast.makeText(this, "Error adding parking", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void preloadParking(int parkingId) {
        Cursor cursor = dbHelper.getParkingById(parkingId);
        if (cursor != null && cursor.moveToFirst()) {
            etParkingName.setText(cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_NAME)));
            etAddress.setText(cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_ADDRESS)));
            etTotalSlots.setText(String.valueOf(cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_TOTAL_SLOTS))));
            currentAvailableSlots = cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_AVAILABLE_SLOTS));
            etPricePerHour.setText(String.valueOf(cursor.getDouble(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_PRICE_PER_HOUR))));
            etFeatures.setText(cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_FEATURES)));
            cursor.close();
        }
    }
}

package com.example.harshatrial;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.database.Cursor;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import java.util.ArrayList;
import java.util.List;

public class AdminDashboardActivity extends AppCompatActivity {

    private RecyclerView rvParkingLocations;
    private DatabaseHelper dbHelper;
    private int userId;
    private ParkingAdapter adapter;
    private List<ParkingLocation> parkingList;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_admin_dashboard);

        dbHelper = new DatabaseHelper(this);
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        userId = sp.getInt("userId", -1);

        rvParkingLocations = findViewById(R.id.rvParkingLocations);
        rvParkingLocations.setLayoutManager(new LinearLayoutManager(this));

        findViewById(R.id.btnAddParking).setOnClickListener(v -> {
            startActivity(new Intent(this, AddParkingActivity.class));
        });

        findViewById(R.id.btnLogout).setOnClickListener(v -> {
            logout();
        });

        loadParkingLocations();
    }

    private void logout() {
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        sp.edit().clear().apply();
        startActivity(new Intent(this, LoginActivity.class));
        finish();
    }

    @Override
    protected void onResume() {
        super.onResume();
        loadParkingLocations();
    }

    public void loadParkingLocations() {
        parkingList = new ArrayList<>();
        Cursor cursor = dbHelper.getParkingByOwner(userId);
        if (cursor != null && cursor.moveToFirst()) {
            do {
                parkingList.add(new ParkingLocation(
                        cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_ID)),
                        cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_OWNER_ID)),
                        cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_NAME)),
                        cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_ADDRESS)),
                        cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_TOTAL_SLOTS)),
                        cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_AVAILABLE_SLOTS)),
                        cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_STATUS))
                ));
            } while (cursor.moveToNext());
            cursor.close();
        }
        adapter = new ParkingAdapter(this, parkingList, true, userId);
        rvParkingLocations.setAdapter(adapter);
    }

    public static class ParkingAdapter extends RecyclerView.Adapter<ParkingAdapter.ViewHolder> {
        private final Context context;
        private final List<ParkingLocation> parkingList;
        private final boolean isAdmin;
        private final int currentUserId;

        public ParkingAdapter(Context context, List<ParkingLocation> parkingList, boolean isAdmin, int currentUserId) {
            this.context = context;
            this.parkingList = parkingList;
            this.isAdmin = isAdmin;
            this.currentUserId = currentUserId;
        }

        @NonNull
        @Override
        public ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
            View view = LayoutInflater.from(context).inflate(R.layout.item_parking, parent, false);
            return new ViewHolder(view);
        }

        @Override
        public void onBindViewHolder(@NonNull ViewHolder holder, int position) {
            ParkingLocation parking = parkingList.get(position);
            holder.tvName.setText(parking.getName());
            holder.tvAddress.setText(parking.getAddress());
            holder.tvSlots.setText("Slots: " + parking.getAvailableSlots() + " / " + parking.getTotalSlots());
            holder.btnAction.setText(isAdmin ? "Refresh" : "Book Now");

            holder.btnAction.setOnClickListener(v -> {
                DatabaseHelper dbHelper = new DatabaseHelper(context);
                if (isAdmin) {
                    if (context instanceof AdminDashboardActivity) {
                        ((AdminDashboardActivity) context).loadParkingLocations();
                    }
                    Toast.makeText(context, "Refreshed", Toast.LENGTH_SHORT).show();
                } else {
                    new AlertDialog.Builder(context)
                            .setTitle("Confirm Booking")
                            .setMessage("Do you want to book a slot at " + parking.getName() + "?")
                            .setPositiveButton("Book", (dialog, which) -> {
                                long bookingId = dbHelper.addBooking(currentUserId, parking.getId());
                                if (bookingId != -1) {
                                    showBookingDetails(parking, bookingId);
                                    if (context instanceof UserDashboardActivity) {
                                        ((UserDashboardActivity) context).loadAllParking();
                                    }
                                } else {
                                    Toast.makeText(context, "No slots available!", Toast.LENGTH_SHORT).show();
                                }
                            })
                            .setNegativeButton("Cancel", null)
                            .show();
                }
            });
        }

        private void showBookingDetails(ParkingLocation parking, long bookingId) {
            new AlertDialog.Builder(context)
                    .setTitle("Booking Confirmed!")
                    .setMessage("Details:\n\n" +
                            "Booking ID: #" + bookingId + "\n" +
                            "Location: " + parking.getName() + "\n" +
                            "Address: " + parking.getAddress() + "\n" +
                            "Status: Confirmed\n\n" +
                            "Please show this at the entrance.")
                    .setPositiveButton("OK", null)
                    .show();
        }

        @Override
        public int getItemCount() { return parkingList.size(); }

        public static class ViewHolder extends RecyclerView.ViewHolder {
            TextView tvName, tvAddress, tvSlots;
            Button btnAction;
            public ViewHolder(@NonNull View itemView) {
                super(itemView);
                tvName = itemView.findViewById(R.id.tvParkingName);
                tvAddress = itemView.findViewById(R.id.tvParkingAddress);
                tvSlots = itemView.findViewById(R.id.tvSlots);
                btnAction = itemView.findViewById(R.id.btnAction);
            }
        }
    }
}

package com.example.harshatrial;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.database.Cursor;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.ContextCompat;

import com.google.android.material.bottomnavigation.BottomNavigationView;
import com.google.android.material.card.MaterialCardView;
import com.google.android.material.progressindicator.LinearProgressIndicator;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

public class AdminDashboardActivity extends AppCompatActivity {

    private RecyclerView rvParkingLocations;
    private DatabaseHelper dbHelper;
    private int userId;
    private ParkingAdapter adapter;
    private List<ParkingLocation> parkingList;
    private TextView tvSummaryOwnerSlotsValue;
    private TextView tvSummaryOwnerLocationsValue;
    private View emptyStateOwner;
    private LinearProgressIndicator progressOwner;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_admin_dashboard);

        dbHelper = new DatabaseHelper(this);
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        userId = sp.getInt("userId", -1);

        rvParkingLocations = findViewById(R.id.rvParkingLocations);
        rvParkingLocations.setLayoutManager(new LinearLayoutManager(this));
        tvSummaryOwnerSlotsValue = findViewById(R.id.tvSummaryOwnerSlotsValue);
        tvSummaryOwnerLocationsValue = findViewById(R.id.tvSummaryOwnerLocationsValue);
        emptyStateOwner = findViewById(R.id.emptyStateOwner);
        progressOwner = findViewById(R.id.progressOwner);

        BottomNavigationView bottomNavAdmin = findViewById(R.id.bottomNavAdmin);
        bottomNavAdmin.setSelectedItemId(R.id.nav_admin_home);
        bottomNavAdmin.setOnItemSelectedListener(item -> {
            if (item.getItemId() == R.id.nav_admin_add) {
                startActivity(new Intent(this, AddParkingActivity.class));
                return true;
            }
            if (item.getItemId() == R.id.nav_admin_home) {
                return true;
            }
            startActivity(new Intent(this, OwnerProfileActivity.class));
            return true;
        });

        tvSummaryOwnerSlotsValue.setOnClickListener(v -> startActivity(new Intent(this, OwnerAnalyticsActivity.class)));
        tvSummaryOwnerLocationsValue.setOnClickListener(v -> startActivity(new Intent(this, OwnerAnalyticsActivity.class)));

        findViewById(R.id.btnAddParking).setOnClickListener(v -> {
            startActivity(new Intent(this, AddParkingActivity.class));
        });

        findViewById(R.id.btnLogout).setOnClickListener(v -> {
            logout();
        });

        loadParkingLocations();
    }

    private void logout() {
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        sp.edit().clear().apply();
        startActivity(new Intent(this, LoginActivity.class));
        finish();
    }

    @Override
    protected void onResume() {
        super.onResume();
        loadParkingLocations();
    }

    public void loadParkingLocations() {
        progressOwner.setVisibility(View.VISIBLE);
        parkingList = new ArrayList<>();
        Cursor cursor = dbHelper.getParkingByOwner(userId);
        if (cursor != null && cursor.moveToFirst()) {
            do {
                parkingList.add(new ParkingLocation(
                        cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_ID)),
                        cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_OWNER_ID)),
                        cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_NAME)),
                        cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_ADDRESS)),
                        cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_TOTAL_SLOTS)),
                        cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_AVAILABLE_SLOTS)),
                        cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_STATUS)),
                        cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_FEATURES)),
                        cursor.getDouble(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_PARKING_PRICE_PER_HOUR))
                ));
            } while (cursor.moveToNext());
            cursor.close();
        }
        adapter = new ParkingAdapter(this, parkingList, true, userId);
        rvParkingLocations.setAdapter(adapter);

        int totalAvailable = 0;
        for (ParkingLocation parkingLocation : parkingList) {
            totalAvailable += parkingLocation.getAvailableSlots();
        }
        tvSummaryOwnerSlotsValue.setText(String.valueOf(totalAvailable));
        tvSummaryOwnerLocationsValue.setText(String.valueOf(parkingList.size()));
        emptyStateOwner.setVisibility(parkingList.isEmpty() ? View.VISIBLE : View.GONE);
        progressOwner.setVisibility(View.GONE);
    }

    public static class ParkingAdapter extends RecyclerView.Adapter<ParkingAdapter.ViewHolder> {
        private final Context context;
        private final List<ParkingLocation> parkingList;
        private final boolean isAdmin;
        private final int currentUserId;

        public ParkingAdapter(Context context, List<ParkingLocation> parkingList, boolean isAdmin, int currentUserId) {
            this.context = context;
            this.parkingList = parkingList;
            this.isAdmin = isAdmin;
            this.currentUserId = currentUserId;
        }

        @NonNull
        @Override
        public ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
            View view = LayoutInflater.from(context).inflate(R.layout.item_parking, parent, false);
            return new ViewHolder(view);
        }

        @Override
        public void onBindViewHolder(@NonNull ViewHolder holder, int position) {
            ParkingLocation parking = parkingList.get(position);
            holder.tvName.setText(parking.getName());
            holder.tvAddress.setText(parking.getAddress());
            holder.tvSlots.setText(context.getString(R.string.parking_slots_template, parking.getAvailableSlots(), parking.getTotalSlots()));
            holder.tvPrice.setText(String.format(Locale.getDefault(), "$%.2f/hr", parking.getPricePerHour()));
            holder.tvFeatures.setText(parking.getFeatures().isEmpty() ? "Standard parking" : parking.getFeatures());

            boolean isAvailable = parking.getAvailableSlots() > 0;
            if (isAvailable) {
                holder.tvStatus.setText(R.string.status_available);
                holder.tvStatus.setTextColor(ContextCompat.getColor(context, R.color.available));
                holder.statusBadge.setCardBackgroundColor(ContextCompat.getColor(context, R.color.availableContainer));
            } else {
                holder.tvStatus.setText(R.string.status_full);
                holder.tvStatus.setTextColor(ContextCompat.getColor(context, R.color.full));
                holder.statusBadge.setCardBackgroundColor(ContextCompat.getColor(context, R.color.fullContainer));
            }

            holder.btnAction.setOnClickListener(v -> {
                if (isAdmin) {
                    Intent editIntent = new Intent(context, AddParkingActivity.class);
                    editIntent.putExtra(AddParkingActivity.EXTRA_PARKING_ID, parking.getId());
                    context.startActivity(editIntent);
                } else {
                    Intent bookingIntent = new Intent(context, BookingDetailsActivity.class);
                    bookingIntent.putExtra("parking_id", parking.getId());
                    bookingIntent.putExtra("parking_name", parking.getName());
                    bookingIntent.putExtra("parking_address", parking.getAddress());
                    bookingIntent.putExtra("parking_price", parking.getPricePerHour());
                    context.startActivity(bookingIntent);
                }
            });

            if (isAdmin) {
                holder.btnAction.setText(R.string.edit);
                holder.btnSecondaryAction.setVisibility(View.VISIBLE);
                holder.btnSecondaryAction.setText(R.string.view_bookings);
                holder.btnSecondaryAction.setOnClickListener(v -> {
                    Intent bookingsIntent = new Intent(context, OwnerBookingsActivity.class);
                    bookingsIntent.putExtra("parking_id", parking.getId());
                    bookingsIntent.putExtra("parking_name", parking.getName());
                    context.startActivity(bookingsIntent);
                });
            } else {
                holder.btnAction.setText(R.string.book_now);
                holder.btnSecondaryAction.setVisibility(View.GONE);
            }
        }

        @Override
        public int getItemCount() { return parkingList.size(); }

        public static class ViewHolder extends RecyclerView.ViewHolder {
            TextView tvName, tvAddress, tvSlots, tvStatus, tvPrice, tvFeatures;
            Button btnAction, btnSecondaryAction;
            MaterialCardView statusBadge;
            public ViewHolder(@NonNull View itemView) {
                super(itemView);
                tvName = itemView.findViewById(R.id.tvParkingName);
                tvAddress = itemView.findViewById(R.id.tvParkingAddress);
                tvSlots = itemView.findViewById(R.id.tvSlots);
                tvStatus = itemView.findViewById(R.id.tvStatus);
                tvPrice = itemView.findViewById(R.id.tvPrice);
                tvFeatures = itemView.findViewById(R.id.tvFeatures);
                statusBadge = itemView.findViewById(R.id.statusBadge);
                btnAction = itemView.findViewById(R.id.btnAction);
                btnSecondaryAction = itemView.findViewById(R.id.btnSecondaryAction);
            }
        }
    }
}

package com.example.harshatrial;

import android.content.Intent;
import android.content.SharedPreferences;
import android.database.Cursor;
import android.os.Bundle;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;

import com.google.android.material.appbar.MaterialToolbar;

import java.util.Locale;

public class BookingDetailsActivity extends AppCompatActivity {

    private DatabaseHelper dbHelper;
    private int userId;
    private int parkingId;
    private String parkingName;
    private String parkingAddress;
    private double parkingPrice;

    private String profileName = "";
    private String profilePhone = "";
    private String profileVehicle = "";

    private EditText etBookingName;
    private EditText etBookingPhone;
    private EditText etBookingVehicle;
    private EditText etBookingHours;
    private TextView tvBookingTotal;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_booking_details);

        dbHelper = new DatabaseHelper(this);
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        userId = sp.getInt("userId", -1);

        parkingId = getIntent().getIntExtra("parking_id", -1);
        parkingName = getIntent().getStringExtra("parking_name");
        parkingAddress = getIntent().getStringExtra("parking_address");
        parkingPrice = getIntent().getDoubleExtra("parking_price", 5.0);

        MaterialToolbar toolbar = findViewById(R.id.toolbar);
        toolbar.setNavigationOnClickListener(v -> finish());

        ((TextView) findViewById(R.id.tvParkingNameDetail)).setText(parkingName);
        ((TextView) findViewById(R.id.tvParkingAddressDetail)).setText(parkingAddress);
        ((TextView) findViewById(R.id.tvPriceDetail)).setText(String.format(Locale.getDefault(), "$%.2f/hr", parkingPrice));

        etBookingName = findViewById(R.id.etBookingName);
        etBookingPhone = findViewById(R.id.etBookingPhone);
        etBookingVehicle = findViewById(R.id.etBookingVehicle);
        etBookingHours = findViewById(R.id.etBookingHours);
        tvBookingTotal = findViewById(R.id.tvBookingTotal);
        CheckBox cbBookForSelf = findViewById(R.id.cbBookForSelf);

        loadUserProfile();
        cbBookForSelf.setChecked(true);
        applyProfileValues(true);
        updateTotal();

        etBookingHours.setOnFocusChangeListener((v, hasFocus) -> {
            if (!hasFocus) {
                updateTotal();
            }
        });

        cbBookForSelf.setOnCheckedChangeListener((buttonView, isChecked) -> applyProfileValues(isChecked));

        findViewById(R.id.btnConfirmBooking).setOnClickListener(v -> confirmBooking());
    }

    private void loadUserProfile() {
        Cursor cursor = dbHelper.getUserById(userId);
        if (cursor != null && cursor.moveToFirst()) {
            profileName = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_NAME));
            profilePhone = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_PHONE));
            profileVehicle = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_VEHICLE));
            cursor.close();
        }
    }

    private void applyProfileValues(boolean useProfile) {
        if (useProfile) {
            etBookingName.setText(profileName);
            etBookingPhone.setText(profilePhone);
            etBookingVehicle.setText(profileVehicle);
        }
    }

    private int getHours() {
        String hoursText = etBookingHours.getText().toString().trim();
        if (hoursText.isEmpty()) {
            return 1;
        }
        return Math.max(1, Integer.parseInt(hoursText));
    }

    private void updateTotal() {
        int hours = getHours();
        double total = hours * parkingPrice;
        tvBookingTotal.setText(String.format(Locale.getDefault(), "Total: $%.2f", total));
    }

    private void confirmBooking() {
        String name = etBookingName.getText().toString().trim();
        String phone = etBookingPhone.getText().toString().trim();
        String vehicle = etBookingVehicle.getText().toString().trim();
        int hours = getHours();

        if (name.isEmpty() || phone.isEmpty()) {
            Toast.makeText(this, "Please add name and phone", Toast.LENGTH_SHORT).show();
            return;
        }

        long bookingId = dbHelper.addBookingDetailed(userId, parkingId, name, phone, vehicle, hours);
        if (bookingId == -1) {
            Toast.makeText(this, "No slots available!", Toast.LENGTH_SHORT).show();
            return;
        }

        String ownerContact = "N/A";
        Cursor owner = dbHelper.getOwnerContactForParking(parkingId);
        if (owner != null && owner.moveToFirst()) {
            String ownerName = owner.getString(owner.getColumnIndexOrThrow("owner_name"));
            String ownerPhone = owner.getString(owner.getColumnIndexOrThrow("owner_phone"));
            ownerContact = ownerName + " - " + (ownerPhone == null || ownerPhone.isEmpty() ? "N/A" : ownerPhone);
            owner.close();
        }

        new AlertDialog.Builder(this)
                .setTitle(getString(R.string.booking_success))
                .setMessage("Booking ID: #" + bookingId + "\n" + getString(R.string.owner_contact, ownerContact))
                .setPositiveButton("View History", (dialog, which) -> {
                    startActivity(new Intent(this, UserBookingHistoryActivity.class));
                    finish();
                })
                .setNegativeButton("Close", (dialog, which) -> finish())
                .show();
    }
}

package com.example.harshatrial;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class DatabaseHelper extends SQLiteOpenHelper {

    private static final String DATABASE_NAME = "Xpot_v3.db";
    private static final int DATABASE_VERSION = 3;

    public static final String TABLE_USERS = "users";
    public static final String COL_USER_ID = "id";
    public static final String COL_USER_NAME = "name";
    public static final String COL_USER_EMAIL = "email";
    public static final String COL_USER_PASSWORD = "password";
    public static final String COL_USER_ROLE = "role";
    public static final String COL_USER_STATUS = "status";

    public static final String TABLE_PARKING = "parking_locations";
    public static final String COL_PARKING_ID = "id";
    public static final String COL_OWNER_ID = "owner_id";
    public static final String COL_PARKING_NAME = "name";
    public static final String COL_PARKING_ADDRESS = "address";
    public static final String COL_TOTAL_SLOTS = "total_slots";
    public static final String COL_AVAILABLE_SLOTS = "available_slots";
    public static final String COL_PARKING_STATUS = "status";

    public static final String TABLE_BOOKINGS = "bookings";
    public static final String COL_BOOKING_ID = "id";
    public static final String COL_BOOKING_USER_ID = "user_id";
    public static final String COL_BOOKING_LOCATION_ID = "location_id";
    public static final String COL_BOOKING_TIME = "booking_time";
    public static final String COL_BOOKING_STATUS = "status";

    public DatabaseHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }

    @Override
    public void onCreate(SQLiteDatabase db) {
        db.execSQL("CREATE TABLE " + TABLE_USERS + " (" +
                COL_USER_ID + " INTEGER PRIMARY KEY AUTOINCREMENT, " +
                COL_USER_NAME + " TEXT, " +
                COL_USER_EMAIL + " TEXT UNIQUE, " +
                COL_USER_PASSWORD + " TEXT, " +
                COL_USER_ROLE + " TEXT, " +
                COL_USER_STATUS + " TEXT)");

        db.execSQL("CREATE TABLE " + TABLE_PARKING + " (" +
                COL_PARKING_ID + " INTEGER PRIMARY KEY AUTOINCREMENT, " +
                COL_OWNER_ID + " INTEGER, " +
                COL_PARKING_NAME + " TEXT, " +
                COL_PARKING_ADDRESS + " TEXT, " +
                COL_TOTAL_SLOTS + " INTEGER, " +
                COL_AVAILABLE_SLOTS + " INTEGER, " +
                COL_PARKING_STATUS + " TEXT)");

        db.execSQL("CREATE TABLE " + TABLE_BOOKINGS + " (" +
                COL_BOOKING_ID + " INTEGER PRIMARY KEY AUTOINCREMENT, " +
                COL_BOOKING_USER_ID + " INTEGER, " +
                COL_BOOKING_LOCATION_ID + " INTEGER, " +
                COL_BOOKING_TIME + " TEXT, " +
                COL_BOOKING_STATUS + " TEXT)");

        // Initial Super Admin
        ContentValues values = new ContentValues();
        values.put(COL_USER_NAME, "Super Admin");
        values.put(COL_USER_EMAIL, "admin@xpot.com");
        values.put(COL_USER_PASSWORD, "admin123");
        values.put(COL_USER_ROLE, "Super Admin");
        values.put(COL_USER_STATUS, "Approved");
        db.insert(TABLE_USERS, null, values);
    }

    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_USERS);
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_PARKING);
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_BOOKINGS);
        onCreate(db);
    }

    public long registerUser(String name, String email, String password, String role, String status) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_USER_NAME, name);
        values.put(COL_USER_EMAIL, email);
        values.put(COL_USER_PASSWORD, password);
        values.put(COL_USER_ROLE, role);
        values.put(COL_USER_STATUS, status);
        return db.insert(TABLE_USERS, null, values);
    }

    public Cursor loginUser(String email, String password) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_USERS + " WHERE " + COL_USER_EMAIL + "=? AND " + COL_USER_PASSWORD + "=?", new String[]{email, password});
    }

    public Cursor getPendingAdmins() {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_USERS + " WHERE " + COL_USER_ROLE + "='Admin' AND " + COL_USER_STATUS + "='Pending'", null);
    }

    public void approveAdmin(int userId) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_USER_STATUS, "Approved");
        db.update(TABLE_USERS, values, COL_USER_ID + "=?", new String[]{String.valueOf(userId)});
    }

    public long addParking(int ownerId, String name, String address, int totalSlots) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_OWNER_ID, ownerId);
        values.put(COL_PARKING_NAME, name);
        values.put(COL_PARKING_ADDRESS, address);
        values.put(COL_TOTAL_SLOTS, totalSlots);
        values.put(COL_AVAILABLE_SLOTS, totalSlots);
        values.put(COL_PARKING_STATUS, "Enabled");
        return db.insert(TABLE_PARKING, null, values);
    }

    public Cursor getParkingByOwner(int ownerId) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_PARKING + " WHERE " + COL_OWNER_ID + "=?", new String[]{String.valueOf(ownerId)});
    }

    public Cursor getAllParking() {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_PARKING + " WHERE " + COL_PARKING_STATUS + "='Enabled'", null);
    }

    public void updateSlots(int parkingId, int availableSlots) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_AVAILABLE_SLOTS, availableSlots);
        db.update(TABLE_PARKING, values, COL_PARKING_ID + "=?", new String[]{String.valueOf(parkingId)});
    }

    public long addBooking(int userId, int locationId) {
        SQLiteDatabase db = this.getWritableDatabase();

        Cursor cursor = db.rawQuery("SELECT " + COL_AVAILABLE_SLOTS + " FROM " + TABLE_PARKING + " WHERE " + COL_PARKING_ID + "=?", new String[]{String.valueOf(locationId)});
        if (cursor != null && cursor.moveToFirst()) {
            int available = cursor.getInt(0);
            if (available > 0) {
                updateSlots(locationId, available - 1);

                ContentValues values = new ContentValues();
                values.put(COL_BOOKING_USER_ID, userId);
                values.put(COL_BOOKING_LOCATION_ID, locationId);
                values.put(COL_BOOKING_TIME, new SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault()).format(new Date()));
                values.put(COL_BOOKING_STATUS, "Confirmed");
                long id = db.insert(TABLE_BOOKINGS, null, values);
                cursor.close();
                return id;
            }
            cursor.close();
        }
        return -1;
    }
}

package com.example.harshatrial;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class DatabaseHelper extends SQLiteOpenHelper {

    private static final String DATABASE_NAME = "Xpot_v4.db";
    private static final int DATABASE_VERSION = 4;

    public static final String TABLE_USERS = "users";
    public static final String COL_USER_ID = "id";
    public static final String COL_USER_NAME = "name";
    public static final String COL_USER_EMAIL = "email";
    public static final String COL_USER_PASSWORD = "password";
    public static final String COL_USER_ROLE = "role";
    public static final String COL_USER_STATUS = "status";
    public static final String COL_USER_PHONE = "phone";
    public static final String COL_USER_VEHICLE = "vehicle_details";

    public static final String TABLE_PARKING = "parking_locations";
    public static final String COL_PARKING_ID = "id";
    public static final String COL_OWNER_ID = "owner_id";
    public static final String COL_PARKING_NAME = "name";
    public static final String COL_PARKING_ADDRESS = "address";
    public static final String COL_TOTAL_SLOTS = "total_slots";
    public static final String COL_AVAILABLE_SLOTS = "available_slots";
    public static final String COL_PARKING_STATUS = "status";
    public static final String COL_PARKING_FEATURES = "features";
    public static final String COL_PARKING_PRICE_PER_HOUR = "price_per_hour";

    public static final String TABLE_BOOKINGS = "bookings";
    public static final String COL_BOOKING_ID = "id";
    public static final String COL_BOOKING_USER_ID = "user_id";
    public static final String COL_BOOKING_LOCATION_ID = "location_id";
    public static final String COL_BOOKING_TIME = "booking_time";
    public static final String COL_BOOKING_STATUS = "status";
    public static final String COL_BOOKING_NAME = "booker_name";
    public static final String COL_BOOKING_PHONE = "booker_phone";
    public static final String COL_BOOKING_VEHICLE = "vehicle_details";
    public static final String COL_BOOKING_HOURS = "hours";
    public static final String COL_BOOKING_TOTAL_PRICE = "total_price";

    public DatabaseHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }

    @Override
    public void onCreate(SQLiteDatabase db) {
        db.execSQL("CREATE TABLE " + TABLE_USERS + " (" +
                COL_USER_ID + " INTEGER PRIMARY KEY AUTOINCREMENT, " +
                COL_USER_NAME + " TEXT, " +
                COL_USER_EMAIL + " TEXT UNIQUE, " +
                COL_USER_PASSWORD + " TEXT, " +
                COL_USER_ROLE + " TEXT, " +
                COL_USER_STATUS + " TEXT, " +
                COL_USER_PHONE + " TEXT DEFAULT '', " +
                COL_USER_VEHICLE + " TEXT DEFAULT '')");

        db.execSQL("CREATE TABLE " + TABLE_PARKING + " (" +
                COL_PARKING_ID + " INTEGER PRIMARY KEY AUTOINCREMENT, " +
                COL_OWNER_ID + " INTEGER, " +
                COL_PARKING_NAME + " TEXT, " +
                COL_PARKING_ADDRESS + " TEXT, " +
                COL_TOTAL_SLOTS + " INTEGER, " +
                COL_AVAILABLE_SLOTS + " INTEGER, " +
                COL_PARKING_STATUS + " TEXT, " +
                COL_PARKING_FEATURES + " TEXT DEFAULT '', " +
                COL_PARKING_PRICE_PER_HOUR + " REAL DEFAULT 5)");

        db.execSQL("CREATE TABLE " + TABLE_BOOKINGS + " (" +
                COL_BOOKING_ID + " INTEGER PRIMARY KEY AUTOINCREMENT, " +
                COL_BOOKING_USER_ID + " INTEGER, " +
                COL_BOOKING_LOCATION_ID + " INTEGER, " +
                COL_BOOKING_TIME + " TEXT, " +
                COL_BOOKING_STATUS + " TEXT, " +
                COL_BOOKING_NAME + " TEXT DEFAULT '', " +
                COL_BOOKING_PHONE + " TEXT DEFAULT '', " +
                COL_BOOKING_VEHICLE + " TEXT DEFAULT '', " +
                COL_BOOKING_HOURS + " INTEGER DEFAULT 1, " +
                COL_BOOKING_TOTAL_PRICE + " REAL DEFAULT 5)");

        // Initial Super Admin
        ContentValues values = new ContentValues();
        values.put(COL_USER_NAME, "Super Admin");
        values.put(COL_USER_EMAIL, "admin@xpot.com");
        values.put(COL_USER_PASSWORD, "admin123");
        values.put(COL_USER_ROLE, "Super Admin");
        values.put(COL_USER_STATUS, "Approved");
        db.insert(TABLE_USERS, null, values);
    }

    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        if (oldVersion < 4) {
            addColumnIfMissing(db, TABLE_USERS, COL_USER_PHONE, "TEXT DEFAULT ''");
            addColumnIfMissing(db, TABLE_USERS, COL_USER_VEHICLE, "TEXT DEFAULT ''");

            addColumnIfMissing(db, TABLE_PARKING, COL_PARKING_FEATURES, "TEXT DEFAULT ''");
            addColumnIfMissing(db, TABLE_PARKING, COL_PARKING_PRICE_PER_HOUR, "REAL DEFAULT 5");

            addColumnIfMissing(db, TABLE_BOOKINGS, COL_BOOKING_NAME, "TEXT DEFAULT ''");
            addColumnIfMissing(db, TABLE_BOOKINGS, COL_BOOKING_PHONE, "TEXT DEFAULT ''");
            addColumnIfMissing(db, TABLE_BOOKINGS, COL_BOOKING_VEHICLE, "TEXT DEFAULT ''");
            addColumnIfMissing(db, TABLE_BOOKINGS, COL_BOOKING_HOURS, "INTEGER DEFAULT 1");
            addColumnIfMissing(db, TABLE_BOOKINGS, COL_BOOKING_TOTAL_PRICE, "REAL DEFAULT 5");
        }
    }

    private void addColumnIfMissing(SQLiteDatabase db, String tableName, String columnName, String typeSql) {
        if (!columnExists(db, tableName, columnName)) {
            db.execSQL("ALTER TABLE " + tableName + " ADD COLUMN " + columnName + " " + typeSql);
        }
    }

    private boolean columnExists(SQLiteDatabase db, String tableName, String columnName) {
        Cursor cursor = db.rawQuery("PRAGMA table_info(" + tableName + ")", null);
        if (cursor != null) {
            while (cursor.moveToNext()) {
                String current = cursor.getString(cursor.getColumnIndexOrThrow("name"));
                if (columnName.equals(current)) {
                    cursor.close();
                    return true;
                }
            }
            cursor.close();
        }
        return false;
    }

    public long registerUser(String name, String email, String password, String role, String status) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_USER_NAME, name);
        values.put(COL_USER_EMAIL, email);
        values.put(COL_USER_PASSWORD, password);
        values.put(COL_USER_ROLE, role);
        values.put(COL_USER_STATUS, status);
        values.put(COL_USER_PHONE, "");
        values.put(COL_USER_VEHICLE, "");
        return db.insert(TABLE_USERS, null, values);
    }

    public Cursor getUserById(int userId) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_USERS + " WHERE " + COL_USER_ID + "=?", new String[]{String.valueOf(userId)});
    }

    public int updateUserProfile(int userId, String name, String phone, String vehicle) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_USER_NAME, name);
        values.put(COL_USER_PHONE, phone);
        values.put(COL_USER_VEHICLE, vehicle);
        return db.update(TABLE_USERS, values, COL_USER_ID + "=?", new String[]{String.valueOf(userId)});
    }

    public Cursor loginUser(String email, String password) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_USERS + " WHERE " + COL_USER_EMAIL + "=? AND " + COL_USER_PASSWORD + "=?", new String[]{email, password});
    }

    public Cursor getPendingAdmins() {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_USERS + " WHERE " + COL_USER_ROLE + "='Admin' AND " + COL_USER_STATUS + "='Pending'", null);
    }

    public void approveAdmin(int userId) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_USER_STATUS, "Approved");
        db.update(TABLE_USERS, values, COL_USER_ID + "=?", new String[]{String.valueOf(userId)});
    }

    public long addParking(int ownerId, String name, String address, int totalSlots) {
        return addParking(ownerId, name, address, totalSlots, "", 5.0);
    }

    public long addParking(int ownerId, String name, String address, int totalSlots, String features, double pricePerHour) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_OWNER_ID, ownerId);
        values.put(COL_PARKING_NAME, name);
        values.put(COL_PARKING_ADDRESS, address);
        values.put(COL_TOTAL_SLOTS, totalSlots);
        values.put(COL_AVAILABLE_SLOTS, totalSlots);
        values.put(COL_PARKING_STATUS, "Enabled");
        values.put(COL_PARKING_FEATURES, features);
        values.put(COL_PARKING_PRICE_PER_HOUR, pricePerHour);
        return db.insert(TABLE_PARKING, null, values);
    }

    public int updateParking(int parkingId, String name, String address, int totalSlots, int availableSlots, String features, double pricePerHour) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_PARKING_NAME, name);
        values.put(COL_PARKING_ADDRESS, address);
        values.put(COL_TOTAL_SLOTS, totalSlots);
        values.put(COL_AVAILABLE_SLOTS, Math.min(availableSlots, totalSlots));
        values.put(COL_PARKING_FEATURES, features);
        values.put(COL_PARKING_PRICE_PER_HOUR, pricePerHour);
        return db.update(TABLE_PARKING, values, COL_PARKING_ID + "=?", new String[]{String.valueOf(parkingId)});
    }

    public Cursor getParkingById(int parkingId) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_PARKING + " WHERE " + COL_PARKING_ID + "=?", new String[]{String.valueOf(parkingId)});
    }

    public Cursor getParkingByOwner(int ownerId) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_PARKING + " WHERE " + COL_OWNER_ID + "=?", new String[]{String.valueOf(ownerId)});
    }

    public Cursor getAllParking() {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_PARKING + " WHERE " + COL_PARKING_STATUS + "='Enabled'", null);
    }

    public void updateSlots(int parkingId, int availableSlots) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues values = new ContentValues();
        values.put(COL_AVAILABLE_SLOTS, availableSlots);
        db.update(TABLE_PARKING, values, COL_PARKING_ID + "=?", new String[]{String.valueOf(parkingId)});
    }

    public long addBooking(int userId, int locationId) {
        Cursor user = getUserById(userId);
        String userName = "";
        String phone = "";
        String vehicle = "";
        if (user != null && user.moveToFirst()) {
            userName = user.getString(user.getColumnIndexOrThrow(COL_USER_NAME));
            phone = user.getString(user.getColumnIndexOrThrow(COL_USER_PHONE));
            vehicle = user.getString(user.getColumnIndexOrThrow(COL_USER_VEHICLE));
            user.close();
        }
        return addBookingDetailed(userId, locationId, userName, phone, vehicle, 1);
    }

    public long addBookingDetailed(int userId, int locationId, String bookerName, String bookerPhone, String vehicleDetails, int hours) {
        SQLiteDatabase db = this.getWritableDatabase();
        Cursor cursor = db.rawQuery("SELECT " + COL_AVAILABLE_SLOTS + ", " + COL_PARKING_PRICE_PER_HOUR + " FROM " + TABLE_PARKING + " WHERE " + COL_PARKING_ID + "=?", new String[]{String.valueOf(locationId)});
        if (cursor != null && cursor.moveToFirst()) {
            int available = cursor.getInt(0);
            double pricePerHour = cursor.getDouble(1);
            if (available > 0) {
                updateSlots(locationId, available - 1);

                ContentValues values = new ContentValues();
                values.put(COL_BOOKING_USER_ID, userId);
                values.put(COL_BOOKING_LOCATION_ID, locationId);
                values.put(COL_BOOKING_TIME, new SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault()).format(new Date()));
                values.put(COL_BOOKING_STATUS, "Confirmed");
                values.put(COL_BOOKING_NAME, bookerName);
                values.put(COL_BOOKING_PHONE, bookerPhone);
                values.put(COL_BOOKING_VEHICLE, vehicleDetails);
                values.put(COL_BOOKING_HOURS, Math.max(1, hours));
                values.put(COL_BOOKING_TOTAL_PRICE, Math.max(1, hours) * pricePerHour);
                long id = db.insert(TABLE_BOOKINGS, null, values);
                cursor.close();
                return id;
            }
            cursor.close();
        }
        return -1;
    }

    public Cursor getBookingsByUser(int userId) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT b." + COL_BOOKING_ID + ", b." + COL_BOOKING_TIME + ", b." + COL_BOOKING_STATUS + ", " +
                        "b." + COL_BOOKING_HOURS + ", b." + COL_BOOKING_TOTAL_PRICE + ", b." + COL_BOOKING_PHONE + ", " +
                        "b." + COL_BOOKING_VEHICLE + ", p." + COL_PARKING_NAME + " AS parking_name, " +
                        "p." + COL_PARKING_ADDRESS + " AS parking_address, u." + COL_USER_NAME + " AS owner_name, " +
                        "u." + COL_USER_PHONE + " AS owner_phone " +
                        "FROM " + TABLE_BOOKINGS + " b " +
                        "JOIN " + TABLE_PARKING + " p ON b." + COL_BOOKING_LOCATION_ID + " = p." + COL_PARKING_ID + " " +
                        "LEFT JOIN " + TABLE_USERS + " u ON p." + COL_OWNER_ID + " = u." + COL_USER_ID + " " +
                        "WHERE b." + COL_BOOKING_USER_ID + "=? ORDER BY b." + COL_BOOKING_ID + " DESC",
                new String[]{String.valueOf(userId)});
    }

    public Cursor getBookingsByOwner(int ownerId) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT b." + COL_BOOKING_ID + ", b." + COL_BOOKING_TIME + ", b." + COL_BOOKING_STATUS + ", " +
                        "b." + COL_BOOKING_NAME + ", b." + COL_BOOKING_PHONE + ", b." + COL_BOOKING_HOURS + ", " +
                        "b." + COL_BOOKING_TOTAL_PRICE + ", p." + COL_PARKING_NAME + " AS parking_name " +
                        "FROM " + TABLE_BOOKINGS + " b " +
                        "JOIN " + TABLE_PARKING + " p ON b." + COL_BOOKING_LOCATION_ID + " = p." + COL_PARKING_ID + " " +
                        "WHERE p." + COL_OWNER_ID + "=? ORDER BY b." + COL_BOOKING_ID + " DESC",
                new String[]{String.valueOf(ownerId)});
    }

    public Cursor getOwnerContactForParking(int parkingId) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT u." + COL_USER_NAME + " AS owner_name, u." + COL_USER_PHONE + " AS owner_phone FROM " + TABLE_PARKING + " p " +
                        "LEFT JOIN " + TABLE_USERS + " u ON p." + COL_OWNER_ID + "=u." + COL_USER_ID + " WHERE p." + COL_PARKING_ID + "=?",
                new String[]{String.valueOf(parkingId)});
    }

    public Cursor getOwnerAnalytics(int ownerId) {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT " +
                        "(SELECT COUNT(*) FROM " + TABLE_PARKING + " WHERE " + COL_OWNER_ID + "=?) AS total_locations, " +
                        "(SELECT COUNT(*) FROM " + TABLE_BOOKINGS + " b JOIN " + TABLE_PARKING + " p ON b." + COL_BOOKING_LOCATION_ID + "=p." + COL_PARKING_ID + " WHERE p." + COL_OWNER_ID + "=?) AS total_bookings, " +
                        "(SELECT IFNULL(SUM(b." + COL_BOOKING_TOTAL_PRICE + "),0) FROM " + TABLE_BOOKINGS + " b JOIN " + TABLE_PARKING + " p ON b." + COL_BOOKING_LOCATION_ID + "=p." + COL_PARKING_ID + " WHERE p." + COL_OWNER_ID + "=?) AS revenue",
                new String[]{String.valueOf(ownerId), String.valueOf(ownerId), String.valueOf(ownerId)});
    }

    public Cursor getSuperAnalytics() {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT " +
                "(SELECT COUNT(*) FROM " + TABLE_USERS + " WHERE " + COL_USER_ROLE + "='Admin') AS owners, " +
                "(SELECT COUNT(*) FROM " + TABLE_USERS + " WHERE " + COL_USER_ROLE + "='Admin' AND " + COL_USER_STATUS + "='Pending') AS pending_owners, " +
                "(SELECT COUNT(*) FROM " + TABLE_PARKING + ") AS total_locations, " +
                "(SELECT COUNT(*) FROM " + TABLE_BOOKINGS + ") AS total_bookings", null);
    }
}

package com.example.harshatrial;

import android.content.Intent;
import android.content.SharedPreferences;
import android.database.Cursor;
import android.os.Bundle;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText etEmail, etPassword;
    private Button btnLogin;
    private TextView tvRegister;
    private DatabaseHelper dbHelper;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        dbHelper = new DatabaseHelper(this);
        etEmail = findViewById(R.id.etEmail);
        etPassword = findViewById(R.id.etPassword);
        btnLogin = findViewById(R.id.btnLogin);
        tvRegister = findViewById(R.id.tvRegister);

        btnLogin.setOnClickListener(v -> {
            String email = etEmail.getText().toString().trim();
            String password = etPassword.getText().toString().trim();

            if (email.isEmpty() || password.isEmpty()) {
                Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
                return;
            }

            Cursor cursor = dbHelper.loginUser(email, password);
            if (cursor != null && cursor.moveToFirst()) {
                int id = cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_ID));
                String name = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_NAME));
                String role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_ROLE));
                String status = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_STATUS));

                if (role.equals("Admin") && !status.equals("Approved")) {
                    Toast.makeText(this, "Your account is pending approval", Toast.LENGTH_SHORT).show();
                } else {
                    saveSession(id, name, email, role);
                    navigateToDashboard(role);
                }
                cursor.close();
            } else {
                Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
            }
        });

        tvRegister.setOnClickListener(v -> {
            startActivity(new Intent(this, RegisterActivity.class));
        });
    }

    private void saveSession(int id, String name, String email, String role) {
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        SharedPreferences.Editor editor = sp.edit();
        editor.putInt("userId", id);
        editor.putString("userName", name);
        editor.putString("userEmail", email);
        editor.putString("userRole", role);
        editor.putBoolean("isLoggedIn", true);
        editor.apply();
    }

    private void navigateToDashboard(String role) {
        Intent intent;
        switch (role) {
            case "Super Admin":
                intent = new Intent(this, SuperAdminDashboardActivity.class);
                break;
            case "Admin":
                intent = new Intent(this, AdminDashboardActivity.class);
                break;
            default:
                intent = new Intent(this, UserDashboardActivity.class);
                break;
        }
        startActivity(intent);
        finish();
    }
}

package com.example.harshatrial;

import android.content.Intent;
import android.content.SharedPreferences;
import android.database.Cursor;
import android.os.Bundle;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText etEmail, etPassword;
    private Button btnLogin;
    private TextView tvRegister;
    private DatabaseHelper dbHelper;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        dbHelper = new DatabaseHelper(this);
        etEmail = findViewById(R.id.etEmail);
        etPassword = findViewById(R.id.etPassword);
        btnLogin = findViewById(R.id.btnLogin);
        tvRegister = findViewById(R.id.tvRegister);

        btnLogin.setOnClickListener(v -> {
            String email = etEmail.getText().toString().trim();
            String password = etPassword.getText().toString().trim();

            if (email.isEmpty() || password.isEmpty()) {
                Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
                return;
            }

            Cursor cursor = dbHelper.loginUser(email, password);
            if (cursor != null && cursor.moveToFirst()) {
                int id = cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_ID));
                String name = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_NAME));
                String role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_ROLE));
                String status = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_STATUS));
                String phone = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_PHONE));
                String vehicle = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_VEHICLE));

                if (role.equals("Admin") && !status.equals("Approved")) {
                    Toast.makeText(this, "Your account is pending approval", Toast.LENGTH_SHORT).show();
                } else {
                    saveSession(id, name, email, role, phone, vehicle);
                    navigateToDashboard(role);
                }
                cursor.close();
            } else {
                Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
            }
        });

        tvRegister.setOnClickListener(v -> {
            startActivity(new Intent(this, RegisterActivity.class));
        });
    }

    private void saveSession(int id, String name, String email, String role, String phone, String vehicle) {
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        SharedPreferences.Editor editor = sp.edit();
        editor.putInt("userId", id);
        editor.putString("userName", name);
        editor.putString("userEmail", email);
        editor.putString("userRole", role);
        editor.putString("userPhone", phone == null ? "" : phone);
        editor.putString("userVehicle", vehicle == null ? "" : vehicle);
        editor.putBoolean("isLoggedIn", true);
        editor.apply();
    }

    private void navigateToDashboard(String role) {
        Intent intent;
        switch (role) {
            case "Super Admin":
                intent = new Intent(this, SuperAdminDashboardActivity.class);
                break;
            case "Admin":
                intent = new Intent(this, AdminDashboardActivity.class);
                break;
            default:
                intent = new Intent(this, UserDashboardActivity.class);
                break;
        }
        startActivity(intent);
        finish();
    }
}

package com.example.harshatrial;

import android.database.Cursor;
import android.os.Bundle;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

import com.google.android.material.appbar.MaterialToolbar;
import com.google.android.material.progressindicator.LinearProgressIndicator;

import java.util.Locale;

public class OwnerAnalyticsActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_owner_analytics);

        MaterialToolbar toolbar = findViewById(R.id.toolbar);
        toolbar.setNavigationOnClickListener(v -> finish());

        int ownerId = getSharedPreferences("UserSession", MODE_PRIVATE).getInt("userId", -1);
        DatabaseHelper dbHelper = new DatabaseHelper(this);
        Cursor cursor = dbHelper.getOwnerAnalytics(ownerId);

        if (cursor != null && cursor.moveToFirst()) {
            int locations = cursor.getInt(cursor.getColumnIndexOrThrow("total_locations"));
            int bookings = cursor.getInt(cursor.getColumnIndexOrThrow("total_bookings"));
            double revenue = cursor.getDouble(cursor.getColumnIndexOrThrow("revenue"));

            ((TextView) findViewById(R.id.tvOwnerAnalyticsLocations)).setText(String.valueOf(locations));
            ((TextView) findViewById(R.id.tvOwnerAnalyticsBookings)).setText(String.valueOf(bookings));
            ((TextView) findViewById(R.id.tvOwnerAnalyticsRevenue)).setText(String.format(Locale.getDefault(), "$%.2f", revenue));

            int revenueScore = normalizeToPercent(revenue, 5000.0);
            int bookingScore = normalizeToPercent(bookings, Math.max(10, locations * 5));
            int locationScore = normalizeToPercent(locations, 20);

            ((TextView) findViewById(R.id.tvRevenueChartValue)).setText(getString(R.string.metric_value_text, getString(R.string.analytics_revenue_label), String.valueOf(revenueScore) + "%"));
            ((TextView) findViewById(R.id.tvBookingsChartValue)).setText(getString(R.string.metric_value_text, getString(R.string.analytics_bookings_label), String.valueOf(bookingScore) + "%"));
            ((TextView) findViewById(R.id.tvLocationsChartValue)).setText(getString(R.string.metric_value_text, getString(R.string.analytics_locations_label), String.valueOf(locationScore) + "%"));

            setProgress(R.id.barRevenue, revenueScore);
            setProgress(R.id.barBookings, bookingScore);
            setProgress(R.id.barLocations, locationScore);

            cursor.close();
        }
    }

    private void setProgress(int viewId, int value) {
        LinearProgressIndicator bar = findViewById(viewId);
        bar.setProgressCompat(Math.max(0, Math.min(100, value)), true);
    }

    private int normalizeToPercent(double value, double max) {
        if (max <= 0) {
            return 0;
        }
        return (int) Math.round((Math.min(value, max) / max) * 100.0);
    }
}

package com.example.harshatrial;

import android.database.Cursor;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.google.android.material.appbar.MaterialToolbar;

import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

public class OwnerBookingsActivity extends AppCompatActivity {

    private final List<String[]> rows = new ArrayList<>();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_owner_bookings);

        MaterialToolbar toolbar = findViewById(R.id.toolbar);
        toolbar.setNavigationOnClickListener(v -> finish());

        RecyclerView rvOwnerBookings = findViewById(R.id.rvOwnerBookings);
        rvOwnerBookings.setLayoutManager(new LinearLayoutManager(this));

        loadBookings();
        rvOwnerBookings.setAdapter(new OwnerBookingsAdapter());
    }

    private void loadBookings() {
        int ownerId = getSharedPreferences("UserSession", MODE_PRIVATE).getInt("userId", -1);
        DatabaseHelper dbHelper = new DatabaseHelper(this);
        Cursor cursor = dbHelper.getBookingsByOwner(ownerId);
        if (cursor != null && cursor.moveToFirst()) {
            do {
                String parking = cursor.getString(cursor.getColumnIndexOrThrow("parking_name"));
                String booker = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_BOOKING_NAME));
                String phone = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_BOOKING_PHONE));
                int hours = cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_BOOKING_HOURS));
                double total = cursor.getDouble(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_BOOKING_TOTAL_PRICE));
                String title = parking + " - " + (booker == null || booker.isEmpty() ? "Guest" : booker);
                String sub = String.format(Locale.getDefault(), "%s | %d hrs | $%.2f", phone == null ? "N/A" : phone, hours, total);
                rows.add(new String[]{title, sub, ""});
            } while (cursor.moveToNext());
            cursor.close();
        }
    }

    private class OwnerBookingsAdapter extends RecyclerView.Adapter<OwnerBookingsAdapter.Holder> {
        @NonNull
        @Override
        public Holder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
            View view = LayoutInflater.from(parent.getContext()).inflate(R.layout.item_booking, parent, false);
            return new Holder(view);
        }

        @Override
        public void onBindViewHolder(@NonNull Holder holder, int position) {
            String[] row = rows.get(position);
            holder.tvTitle.setText(row[0]);
            holder.tvSub.setText(row[1]);
            holder.tvOwner.setVisibility(View.GONE);
        }

        @Override
        public int getItemCount() {
            return rows.size();
        }

        class Holder extends RecyclerView.ViewHolder {
            TextView tvTitle;
            TextView tvSub;
            TextView tvOwner;

            Holder(@NonNull View itemView) {
                super(itemView);
                tvTitle = itemView.findViewById(R.id.tvBookingTitle);
                tvSub = itemView.findViewById(R.id.tvBookingSub);
                tvOwner = itemView.findViewById(R.id.tvBookingOwnerContact);
            }
        }
    }
}

package com.example.harshatrial;

import android.content.SharedPreferences;
import android.database.Cursor;
import android.os.Bundle;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.google.android.material.appbar.MaterialToolbar;

public class OwnerProfileActivity extends AppCompatActivity {

    private EditText etProfileName;
    private EditText etProfileEmail;
    private EditText etProfilePhone;
    private EditText etProfileVehicle;
    private DatabaseHelper dbHelper;
    private int userId;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_owner_profile);

        dbHelper = new DatabaseHelper(this);
        SharedPreferences sp = getSharedPreferences("UserSession", MODE_PRIVATE);
        userId = sp.getInt("userId", -1);

        MaterialToolbar toolbar = findViewById(R.id.toolbar);
        toolbar.setNavigationOnClickListener(v -> finish());
        toolbar.setTitle(R.string.profile_title);

        etProfileName = findViewById(R.id.etProfileName);
        etProfileEmail = findViewById(R.id.etProfileEmail);
        etProfilePhone = findViewById(R.id.etProfilePhone);
        etProfileVehicle = findViewById(R.id.etProfileVehicle);

        loadProfile();

        findViewById(R.id.btnSaveProfile).setOnClickListener(v -> {
            String name = etProfileName.getText().toString().trim();
            String phone = etProfilePhone.getText().toString().trim();
            String vehicle = etProfileVehicle.getText().toString().trim();

            if (name.isEmpty()) {
                Toast.makeText(this, "Name is required", Toast.LENGTH_SHORT).show();
                return;
            }

            int updated = dbHelper.updateUserProfile(userId, name, phone, vehicle);
            if (updated > 0) {
                sp.edit().putString("userName", name).putString("userPhone", phone).putString("userVehicle", vehicle).apply();
                Toast.makeText(this, "Profile updated", Toast.LENGTH_SHORT).show();
                finish();
            } else {
                Toast.makeText(this, "Unable to update profile", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void loadProfile() {
        Cursor cursor = dbHelper.getUserById(userId);
        if (cursor != null && cursor.moveToFirst()) {
            etProfileName.setText(cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_NAME)));
            etProfileEmail.setText(cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_EMAIL)));
            etProfilePhone.setText(cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_PHONE)));
            etProfileVehicle.setText(cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.COL_USER_VEHICLE)));
            cursor.close();
        }
    }
}

package com.example.harshatrial;

public class ParkingLocation {
    private int id;
    private int ownerId;
    private String name;
    private String address;
    private int totalSlots;
    private int availableSlots;
    private String status;

    public ParkingLocation(int id, int ownerId, String name, String address, int totalSlots, int availableSlots, String status) {
        this.id = id;
        this.ownerId = ownerId;
        this.name = name;
        this.address = address;
        this.totalSlots = totalSlots;
        this.availableSlots = availableSlots;
        this.status = status;
    }

    public int getId() { return id; }
    public int getOwnerId() { return ownerId; }
    public String getName() { return name; }
    public String getAddress() { return address; }
    public int getTotalSlots() { return totalSlots; }
    public int getAvailableSlots() { return availableSlots; }
    public String getStatus() { return status; }
}

